-- KORYXA FORMATION — POWER BI DATA ANALYST — CHANTIER 4
-- Quiz, test final et projet final. Contenus non publiés.

ALTER TABLE public.quiz_questions ADD COLUMN IF NOT EXISTS question_type TEXT NOT NULL DEFAULT 'qcm' CHECK (question_type IN ('qcm','true_false','comprehension','mini_challenge')), ADD COLUMN IF NOT EXISTS is_final_test BOOLEAN NOT NULL DEFAULT FALSE;

WITH tm AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='power-bi-data-analyst' AND m.order_index=0), seed(order_index,question_type,question,options,answer,skill,explanation) AS (VALUES (1,'qcm','Quelle vue sert à construire les visuels ?',jsonb_build_array('A) Rapport','B) Données','C) Modèle','D) Power Query'),'A','interface','La bonne réponse est Rapport.'),(2,'true_false','Power BI Desktop permet de préparer les données et créer des rapports.',jsonb_build_array('A) Vrai','B) Faux','C) Seulement en ligne','D) Seulement sur mobile'),'A','écosystème','La bonne réponse est Vrai.'),(3,'comprehension','Quel composant héberge rapports et modèles dans le cloud ?',jsonb_build_array('A) Power BI Service','B) Excel Online','C) OneDrive seul','D) Word'),'A','service','La bonne réponse est Power BI Service.'),(4,'mini_challenge','Avant le premier visuel, quelle action est prioritaire ?',jsonb_build_array('A) Contrôler les données chargées','B) Choisir dix couleurs','C) Publier immédiatement','D) Ajouter une animation'),'A','workflow','La bonne réponse est Contrôler les données chargées.')) INSERT INTO public.quiz_questions(module_id,order_index,question_type,question,options,answer,difficulty,skill,explanation,is_active,is_final_test) SELECT tm.id,s.order_index,s.question_type,s.question,s.options,s.answer,CASE WHEN s.question_type='mini_challenge' THEN 'avance' WHEN s.question_type='comprehension' THEN 'intermediaire' ELSE 'debutant' END,s.skill,s.explanation,FALSE,FALSE FROM tm CROSS JOIN seed s ON CONFLICT(module_id,order_index) DO UPDATE SET question_type=EXCLUDED.question_type,question=EXCLUDED.question,options=EXCLUDED.options,answer=EXCLUDED.answer,difficulty=EXCLUDED.difficulty,skill=EXCLUDED.skill,explanation=EXCLUDED.explanation,is_active=FALSE,is_final_test=FALSE;

WITH tm AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='power-bi-data-analyst' AND m.order_index=1), seed(order_index,question_type,question,options,answer,skill,explanation) AS (VALUES (1,'qcm','Quelle étape définit correctement une colonne de dates ?',jsonb_build_array('A) Modifier le type en Date','B) La renommer Date','C) La trier','D) La masquer'),'A','types','La bonne réponse est Modifier le type en Date.'),(2,'true_false','Supprimer les doublons sans clé métier est toujours sûr.',jsonb_build_array('A) Faux','B) Vrai','C) Seulement en CSV','D) Seulement dans Excel'),'A','qualité','La bonne réponse est Faux.'),(3,'comprehension','Pourquoi conserver des étapes explicites ?',jsonb_build_array('A) Pour rendre la transformation auditable','B) Pour alourdir le fichier','C) Pour bloquer l’actualisation','D) Pour supprimer les sources'),'A','traçabilité','La bonne réponse est Pour rendre la transformation auditable.'),(4,'mini_challenge','Une colonne contient des erreurs de conversion. Première action ?',jsonb_build_array('A) Identifier les valeurs fautives','B) Remplacer tout par zéro','C) Masquer la colonne','D) Publier'),'A','erreurs','La bonne réponse est Identifier les valeurs fautives.')) INSERT INTO public.quiz_questions(module_id,order_index,question_type,question,options,answer,difficulty,skill,explanation,is_active,is_final_test) SELECT tm.id,s.order_index,s.question_type,s.question,s.options,s.answer,CASE WHEN s.question_type='mini_challenge' THEN 'avance' WHEN s.question_type='comprehension' THEN 'intermediaire' ELSE 'debutant' END,s.skill,s.explanation,FALSE,FALSE FROM tm CROSS JOIN seed s ON CONFLICT(module_id,order_index) DO UPDATE SET question_type=EXCLUDED.question_type,question=EXCLUDED.question,options=EXCLUDED.options,answer=EXCLUDED.answer,difficulty=EXCLUDED.difficulty,skill=EXCLUDED.skill,explanation=EXCLUDED.explanation,is_active=FALSE,is_final_test=FALSE;

