WITH tm AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='power-bi-data-analyst' AND m.order_index=10), seed(order_index,question_type,question,options,answer,skill,explanation) AS (VALUES (1,'qcm','Où publie-t-on un rapport pour collaborer ?',jsonb_build_array('A) Dans un espace de travail Power BI','B) Dans le Presse-papiers','C) Dans Word','D) Dans Paint'),'A','service','La bonne réponse est Dans un espace de travail Power BI.'),(2,'true_false','Publier sur le web convient aux données confidentielles.',jsonb_build_array('A) Faux','B) Vrai','C) Toujours','D) Seulement avec RLS'),'A','partage','La bonne réponse est Faux.'),(3,'comprehension','Que faut-il configurer pour une source locale ?',jsonb_build_array('A) Une passerelle et des identifiants valides','B) Une image','C) Un signet','D) Un thème'),'A','actualisation','La bonne réponse est Une passerelle et des identifiants valides.'),(4,'mini_challenge','Après publication, quel contrôle est prioritaire ?',jsonb_build_array('A) Tester accès et actualisation','B) Changer toutes les couleurs','C) Supprimer le modèle','D) Masquer les erreurs'),'A','recette','La bonne réponse est Tester accès et actualisation.')) INSERT INTO public.quiz_questions(module_id,order_index,question_type,question,options,answer,difficulty,skill,explanation,is_active,is_final_test) SELECT tm.id,s.order_index,s.question_type,s.question,s.options,s.answer,CASE WHEN s.question_type='mini_challenge' THEN 'avance' WHEN s.question_type='comprehension' THEN 'intermediaire' ELSE 'debutant' END,s.skill,s.explanation,FALSE,FALSE FROM tm CROSS JOIN seed s ON CONFLICT(module_id,order_index) DO UPDATE SET question_type=EXCLUDED.question_type,question=EXCLUDED.question,options=EXCLUDED.options,answer=EXCLUDED.answer,difficulty=EXCLUDED.difficulty,skill=EXCLUDED.skill,explanation=EXCLUDED.explanation,is_active=FALSE,is_final_test=FALSE;

WITH tm AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='power-bi-data-analyst' AND m.order_index=11), seed(order_index,question_type,question,options,answer,skill,explanation) AS (VALUES (1,'qcm','Quel mécanisme limite les données visibles par utilisateur ?',jsonb_build_array('A) RLS','B) Drill-down','C) Signets','D) Info-bulles'),'A','sécurité','La bonne réponse est RLS.'),(2,'true_false','Le rôle RLS doit être testé avec Afficher comme rôle.',jsonb_build_array('A) Vrai','B) Faux','C) Seulement après incident','D) Jamais'),'A','test','La bonne réponse est Vrai.'),(3,'comprehension','Quel outil aide à repérer les visuels lents ?',jsonb_build_array('A) Analyseur de performances','B) Éditeur de thème','C) Navigateur','D) Zoom'),'A','performance','La bonne réponse est Analyseur de performances.'),(4,'mini_challenge','Avant remise, quelle documentation est essentielle ?',jsonb_build_array('A) Sources, mesures, accès et actualisation','B) Seulement le logo','C) Seulement les couleurs','D) Aucune'),'A','documentation','La bonne réponse est Sources, mesures, accès et actualisation.')) INSERT INTO public.quiz_questions(module_id,order_index,question_type,question,options,answer,difficulty,skill,explanation,is_active,is_final_test) SELECT tm.id,s.order_index,s.question_type,s.question,s.options,s.answer,CASE WHEN s.question_type='mini_challenge' THEN 'avance' WHEN s.question_type='comprehension' THEN 'intermediaire' ELSE 'debutant' END,s.skill,s.explanation,FALSE,FALSE FROM tm CROSS JOIN seed s ON CONFLICT(module_id,order_index) DO UPDATE SET question_type=EXCLUDED.question_type,question=EXCLUDED.question,options=EXCLUDED.options,answer=EXCLUDED.answer,difficulty=EXCLUDED.difficulty,skill=EXCLUDED.skill,explanation=EXCLUDED.explanation,is_active=FALSE,is_final_test=FALSE;

WITH tm AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='power-bi-data-analyst' AND m.order_index=11), seed(order_index,question_type,question,options,answer,skill,explanation) AS (VALUES (101,'qcm','Quel outil prépare et combine les sources ?',jsonb_build_array('A) Power Query','B) RLS','C) Signets','D) DAX Studio'),'A','synthèse','La bonne réponse est Power Query.'),(102,'qcm','Quel modèle est recommandé ?',jsonb_build_array('A) Schéma en étoile','B) Table unique avec sous-totaux','C) Relations bidirectionnelles partout','D) Aucune relation'),'A','synthèse','La bonne réponse est Schéma en étoile.'),(103,'qcm','Quelle expression calcule un taux sans erreur de division ?',jsonb_build_array('A) DIVIDE','B) FORMAT','C) LEFT','D) COUNT'),'A','synthèse','La bonne réponse est DIVIDE.'),(104,'qcm','Quel élément rend les analyses temporelles fiables ?',jsonb_build_array('A) Une table calendrier continue','B) Une colonne texte seule','C) Un segment caché','D) Une image'),'A','synthèse','La bonne réponse est Une table calendrier continue.'),(105,'qcm','Quel visuel montre une tendance ?',jsonb_build_array('A) Courbe','B) Secteur 3D','C) Carte sans géographie','D) Zone de texte'),'A','synthèse','La bonne réponse est Courbe.'),(106,'qcm','Quel mécanisme sécurise par région ?',jsonb_build_array('A) RLS','B) Drill-through','C) Signet','D) Thème'),'A','synthèse','La bonne réponse est RLS.'),(107,'qcm','Que faut-il tester après publication ?',jsonb_build_array('A) Accès et actualisation','B) Uniquement les couleurs','C) Uniquement le titre','D) Rien'),'A','synthèse','La bonne réponse est Accès et actualisation.'),(108,'qcm','Quel indicateur mesure la rentabilité ?',jsonb_build_array('A) Marge','B) Nombre de pages','C) Nombre de visuels','D) Taille du fichier'),'A','synthèse','La bonne réponse est Marge.'),(109,'qcm','Que doit contenir une documentation professionnelle ?',jsonb_build_array('A) Sources, mesures et actualisation','B) Seulement le logo','C) Seulement les couleurs','D) Aucune procédure'),'A','synthèse','La bonne réponse est Sources, mesures et actualisation.'),(110,'qcm','Quel outil identifie un visuel lent ?',jsonb_build_array('A) Analyseur de performances','B) Power Query uniquement','C) Éditeur de thème','D) Navigateur'),'A','synthèse','La bonne réponse est Analyseur de performances.'),(111,'qcm','Quel livrable prouve la compétence finale ?',jsonb_build_array('A) Un rapport actualisable, sécurisé et documenté','B) Une capture d’écran','C) Une liste de fonctions','D) Une page vide'),'A','synthèse','La bonne réponse est Un rapport actualisable, sécurisé et documenté.'),(112,'qcm','Le projet final doit-il répondre à des questions métier ?',jsonb_build_array('A) Oui','B) Non','C) Seulement si demandé','D) Seulement sur mobile'),'A','synthèse','La bonne réponse est Oui.')) INSERT INTO public.quiz_questions(module_id,order_index,question_type,question,options,answer,difficulty,skill,explanation,is_active,is_final_test) SELECT tm.id,s.order_index,s.question_type,s.question,s.options,s.answer,'intermediaire',s.skill,s.explanation,FALSE,TRUE FROM tm CROSS JOIN seed s ON CONFLICT(module_id,order_index) DO UPDATE SET question_type=EXCLUDED.question_type,question=EXCLUDED.question,options=EXCLUDED.options,answer=EXCLUDED.answer,difficulty=EXCLUDED.difficulty,skill=EXCLUDED.skill,explanation=EXCLUDED.explanation,is_active=FALSE,is_final_test=TRUE;


WITH c AS (SELECT id FROM public.courses WHERE slug='power-bi-data-analyst')
INSERT INTO public.course_projects(course_id,slug,title,summary,brief_md,corpus_policy_md,starter_assets,minimum_version,advanced_version,functional_criteria,technical_criteria,rubric,reference_solution_md,is_published)
SELECT c.id,'dashboard-pilotage-commercial-power-bi','Dashboard de pilotage commercial avec Power BI','Construire un rapport Power BI professionnel, actualisable, sécurisé et orienté décision à partir de quatre mois de ventes.','# Brief\n\nVous êtes Data Analyst. La direction souhaite piloter chiffre d’affaires, marge, volume, produits, clients et régions. Vous devez consolider les fichiers mensuels, construire un modèle en étoile, créer les mesures DAX, concevoir un rapport multi-pages, publier une version de test et documenter sécurité et actualisation.\n\n## Livrables\n- fichier PBIX ;\n- modèle de données ;\n- mesures DAX ;\n- rapport Synthèse, Produits, Clients et Détails ;\n- vue mobile ;\n- procédure de publication et actualisation ;\n- tests RLS ;\n- trois recommandations métier.','# Politique des données\n\nUtiliser uniquement les fichiers pédagogiques fournis. Ne publier aucune donnée sensible sur le web. Documenter les transformations et les règles de sécurité.','[{"path":"/resources/power-bi-data-analyst/01_sources_et_referentiels.xlsx","purpose":"Référentiels"},{"path":"/resources/power-bi-data-analyst/02_modele_donnees.xlsx","purpose":"Dictionnaire du modèle"},{"path":"/resources/power-bi-data-analyst/03_dax_kpi.xlsx","purpose":"Mesures et objectifs"},{"path":"/resources/power-bi-data-analyst/04_cahier_dashboard.xlsx","purpose":"Cahier des pages"},{"path":"/resources/power-bi-data-analyst/ventes_2026_01.csv","purpose":"Janvier"},{"path":"/resources/power-bi-data-analyst/ventes_2026_02.csv","purpose":"Février"},{"path":"/resources/power-bi-data-analyst/ventes_2026_03.csv","purpose":"Mars"},{"path":"/resources/power-bi-data-analyst/ventes_2026_04.csv","purpose":"Avril"}]'::jsonb,'["Consolider les quatre CSV","Créer le modèle en étoile","Créer au moins huit mesures DAX","Construire quatre pages de rapport","Configurer la vue mobile","Tester un rôle RLS","Rédiger trois recommandations"]'::jsonb,'["Ajouter objectifs et écarts","Créer comparaisons temporelles","Optimiser avec Analyseur de performances","Configurer une actualisation planifiée","Documenter une stratégie de déploiement"]'::jsonb,'["Les quatre mois sont consolidés","Les KPI réagissent aux filtres","Le rapport répond aux questions métier","La vue mobile est exploitable","Les recommandations reposent sur les résultats"]'::jsonb,'["Requêtes nommées et typées","Relations sans ambiguïté","Mesures centralisées","RLS testé","Aucun visuel lent critique","Publication et actualisation documentées"]'::jsonb,'[{"criterion":"Préparation et qualité des données","points":10},{"criterion":"Modèle en étoile","points":10},{"criterion":"Mesures DAX et KPI","points":12},{"criterion":"Rapport et expérience utilisateur","points":10},{"criterion":"Publication, sécurité et performance","points":10},{"criterion":"Analyse et documentation","points":8}]'::jsonb,'# Solution de référence\n\nLa solution attendue consolide les fichiers avec Power Query, utilise un modèle en étoile avec DimDate, centralise les mesures dans une table dédiée, limite les pages aux questions métier, configure la vue mobile, teste RLS et documente publication et actualisation.',FALSE FROM c
ON CONFLICT(course_id,slug) DO UPDATE SET title=EXCLUDED.title,summary=EXCLUDED.summary,brief_md=EXCLUDED.brief_md,corpus_policy_md=EXCLUDED.corpus_policy_md,starter_assets=EXCLUDED.starter_assets,minimum_version=EXCLUDED.minimum_version,advanced_version=EXCLUDED.advanced_version,functional_criteria=EXCLUDED.functional_criteria,technical_criteria=EXCLUDED.technical_criteria,rubric=EXCLUDED.rubric,reference_solution_md=EXCLUDED.reference_solution_md,is_published=FALSE;

WITH p AS (SELECT cp.id project_id,cp.course_id FROM public.course_projects cp JOIN public.courses c ON c.id=cp.course_id WHERE c.slug='power-bi-data-analyst' AND cp.slug='dashboard-pilotage-commercial-power-bi'), seed(module_order,slug,title,description,deliverables,acceptance,ord) AS (VALUES
(1,'preparer-donnees','Préparer les données','Nettoyer, typer et documenter les sources.','["Requêtes Power Query","Contrôles qualité"]'::jsonb,'["Types corrects","Doublons contrôlés","Étapes explicites"]'::jsonb,0),
(2,'consolider-sources','Consolider les fichiers','Combiner les quatre mois et enrichir les ventes.','["FaitVentes consolidée","Référentiels fusionnés"]'::jsonb,'["120 ventes chargées","Aucune jointure perdue"]'::jsonb,1),
(3,'modele-etoile','Construire le modèle','Créer faits, dimensions et relations.','["Modèle en étoile","Schéma documenté"]'::jsonb,'["Relations 1:*","Aucune ambiguïté"]'::jsonb,2),
(5,'mesures-dax','Créer les mesures','Construire CA, marge, volume, clients et panier moyen.','["Table Mesures","Formats métier"]'::jsonb,'["Au moins huit mesures","Résultats contrôlés"]'::jsonb,3),
(7,'analyse-temporelle','Ajouter les comparaisons','Créer cumul, période précédente et évolution.','["Mesures temporelles","Courbe mensuelle"]'::jsonb,'["DimDate marquée","Comparaisons cohérentes"]'::jsonb,4),
(9,'rapport-final','Assembler le rapport','Créer les pages et la vue mobile.','["Quatre pages","Navigation","Vue mobile"]'::jsonb,'["Interactions testées","Lecture claire"]'::jsonb,5),
(11,'securite-recette','Sécuriser et remettre','Tester RLS, performance, publication et documentation.','["Rôle RLS","Rapport final","Guide de remise"]'::jsonb,'["RLS validé","Aucun blocage","Actualisation documentée","Trois recommandations"]'::jsonb,6))
INSERT INTO public.course_project_milestones(project_id,module_id,slug,title,description,deliverables,acceptance_criteria,order_index,is_published)
SELECT p.project_id,m.id,s.slug,s.title,s.description,s.deliverables,s.acceptance,s.ord,FALSE FROM p JOIN public.modules m ON m.course_id=p.course_id JOIN seed s ON s.module_order=m.order_index
ON CONFLICT(project_id,slug) DO UPDATE SET module_id=EXCLUDED.module_id,title=EXCLUDED.title,description=EXCLUDED.description,deliverables=EXCLUDED.deliverables,acceptance_criteria=EXCLUDED.acceptance_criteria,order_index=EXCLUDED.order_index,is_published=FALSE;

DO $$ DECLARE quiz_count INT; final_count INT; project_count INT; milestone_count INT; rubric_total INT; BEGIN
SELECT COUNT(*) INTO quiz_count FROM public.quiz_questions q JOIN public.modules m ON m.id=q.module_id JOIN public.courses c ON c.id=m.course_id WHERE c.slug='power-bi-data-analyst' AND q.is_final_test=FALSE;
SELECT COUNT(*) INTO final_count FROM public.quiz_questions q JOIN public.modules m ON m.id=q.module_id JOIN public.courses c ON c.id=m.course_id WHERE c.slug='power-bi-data-analyst' AND q.is_final_test=TRUE;
SELECT COUNT(*) INTO project_count FROM public.course_projects cp JOIN public.courses c ON c.id=cp.course_id WHERE c.slug='power-bi-data-analyst';
SELECT COUNT(*) INTO milestone_count FROM public.course_project_milestones pm JOIN public.course_projects cp ON cp.id=pm.project_id JOIN public.courses c ON c.id=cp.course_id WHERE c.slug='power-bi-data-analyst';
SELECT COALESCE(SUM((item->>'points')::INT),0) INTO rubric_total FROM public.course_projects cp JOIN public.courses c ON c.id=cp.course_id,LATERAL jsonb_array_elements(cp.rubric) item WHERE c.slug='power-bi-data-analyst';
IF quiz_count<>48 OR final_count<>12 OR project_count<>1 OR milestone_count<>7 OR rubric_total<>60 THEN RAISE EXCEPTION 'Chantier 4 Power BI incomplet: quiz %, final %, projets %, jalons %, barème %',quiz_count,final_count,project_count,milestone_count,rubric_total; END IF; END $$;
